import { createHash } from 'node:crypto';

function serialize(value, seen) {
  if (value === null) return 'null';
  if (typeof value === 'boolean' || typeof value === 'string') return JSON.stringify(value);
  if (typeof value === 'number') {
    if (!Number.isFinite(value)) throw new TypeError('canonical JSON requires finite numbers');
    return JSON.stringify(value);
  }
  if (typeof value !== 'object') throw new TypeError(`unsupported JSON value: ${typeof value}`);
  if (seen.has(value)) throw new TypeError('cyclic JSON value');
  seen.add(value);
  try {
    if (Array.isArray(value)) return `[${value.map((item) => serialize(item, seen)).join(',')}]`;
    return `{${Object.keys(value).sort().map((key) => `${JSON.stringify(key)}:${serialize(value[key], seen)}`).join(',')}}`;
  } finally {
    seen.delete(value);
  }
}

export function canonicalJson(value) {
  return serialize(value, new WeakSet());
}

export function payloadDigest(value) {
  return createHash('sha256').update(canonicalJson(value), 'utf8').digest('hex');
}

