function clone(value) {
  return value === undefined ? undefined : structuredClone(value);
}

export class MemoryLedgerStore {
  #records = new Map();
  #outbox = [];

  async getRecord(key) { return clone(this.#records.get(key)); }
  async putRecord(key, record) { this.#records.set(key, clone(record)); }
  async appendOutbox(message) { this.#outbox.push(clone(message)); }
  async getOutbox() { return clone(this.#outbox); }
  async getAllRecords() { return clone([...this.#records.values()]); }
}

