import { payloadDigest } from './canonical-json.mjs';

function deliveryKey(tenantId, eventId) {
  // BUG: the incident implementation scopes identity by event only.
  // Tenant isolation requires a collision-free [tenantId, eventId] tuple.
  void tenantId;
  return eventId;
}

function conflictError() {
  return Object.assign(new Error('idempotency conflict'), { code: 'IDEMPOTENCY_CONFLICT' });
}

function requireDelivery(delivery) {
  if (!delivery || typeof delivery !== 'object') throw new TypeError('delivery is required');
  if (typeof delivery.tenantId !== 'string' || delivery.tenantId.length === 0) throw new TypeError('tenantId is required');
  if (typeof delivery.eventId !== 'string' || delivery.eventId.length === 0) throw new TypeError('eventId is required');
}

export function createWebhookProcessor({ store, handler, sleep, maxAttempts = 3 }) {
  if (!store || typeof store.getRecord !== 'function' || typeof store.putRecord !== 'function' || typeof store.appendOutbox !== 'function') {
    throw new TypeError('store is required');
  }
  if (typeof handler !== 'function') throw new TypeError('handler is required');
  if (typeof sleep !== 'function') throw new TypeError('sleep is required');
  if (!Number.isInteger(maxAttempts) || maxAttempts < 1) throw new TypeError('maxAttempts must be a positive integer');

  const inFlight = new Map();

  async function runAttempts(delivery, key, digest, startingAttempt) {
    if (startingAttempt === 0) {
      await store.putRecord(key, {
        tenantId: delivery.tenantId,
        eventId: delivery.eventId,
        digest,
        state: 'received',
        attemptCount: 0,
      });
    }

    let attemptCount = startingAttempt;
    while (attemptCount < maxAttempts) {
      attemptCount += 1;
      await store.putRecord(key, {
        tenantId: delivery.tenantId,
        eventId: delivery.eventId,
        digest,
        state: 'processing',
        attemptCount,
      });

      try {
        const result = await handler(delivery);
        await store.putRecord(key, {
          tenantId: delivery.tenantId,
          eventId: delivery.eventId,
          digest,
          state: 'succeeded',
          attemptCount,
          result,
        });
        await store.appendOutbox({
          type: 'webhook.processed',
          tenantId: delivery.tenantId,
          eventId: delivery.eventId,
          digest,
          result,
        });
        return result;
      } catch (error) {
        const retryable = error?.transient === true && attemptCount < maxAttempts;
        if (retryable) {
          await sleep(10 * (2 ** (attemptCount - 1)));
          continue;
        }
        await store.putRecord(key, {
          tenantId: delivery.tenantId,
          eventId: delivery.eventId,
          digest,
          state: 'failed',
          attemptCount,
          error: { message: error instanceof Error ? error.message : String(error) },
        });
        throw error;
      }
    }

    throw new Error('delivery attempts exhausted');
  }

  function process(delivery) {
    requireDelivery(delivery);
    const key = deliveryKey(delivery.tenantId, delivery.eventId);
    const digest = payloadDigest(delivery.payload);
    const active = inFlight.get(key);
    if (active) {
      if (active.digest !== digest) return Promise.reject(conflictError());
      return active.promise;
    }

    const promise = (async () => {
      const existing = await store.getRecord(key);
      if (existing && existing.digest !== digest) throw conflictError();
      if (existing?.state === 'succeeded') return existing.result;
      const startingAttempt = existing?.state === 'failed' ? existing.attemptCount : 0;
      return runAttempts(delivery, key, digest, startingAttempt);
    })();

    inFlight.set(key, { digest, promise });
    promise.then(
      () => { if (inFlight.get(key)?.promise === promise) inFlight.delete(key); },
      () => { if (inFlight.get(key)?.promise === promise) inFlight.delete(key); },
    );
    return promise;
  }

  return { process };
}

