import test from 'node:test';
import assert from 'node:assert/strict';
import { mkdir, writeFile } from 'node:fs/promises';
import { canonicalJson, createWebhookProcessor, MemoryLedgerStore, payloadDigest } from '../src/index.mjs';

function setup(handler, extra = {}) {
  const store = new MemoryLedgerStore();
  const sleeps = [];
  const processor = createWebhookProcessor({ store, handler, sleep: async (ms) => { sleeps.push(ms); }, ...extra });
  return { store, sleeps, processor };
}

test('canonical JSON is deep, deterministic, and array-order sensitive', () => {
  assert.equal(canonicalJson({ z: 1, a: { y: 2, x: [3, { b: true, a: null }] } }), '{"a":{"x":[3,{"a":null,"b":true}],"y":2},"z":1}');
  assert.equal(payloadDigest({ b: 2, a: 1 }), payloadDigest({ a: 1, b: 2 }));
  assert.notEqual(payloadDigest({ a: [1, 2] }), payloadDigest({ a: [2, 1] }));
  assert.throws(() => canonicalJson({ bad: undefined }), TypeError);
  assert.throws(() => canonicalJson(Number.NaN), TypeError);
  const cyclic = {}; cyclic.self = cyclic; assert.throws(() => canonicalJson(cyclic), TypeError);
});

test('success persists state and appends exactly one outbox message', async () => {
  const { processor, store } = setup(async ({ payload }) => ({ invoiceId: payload.invoiceId, accepted: true }));
  const value = await processor.process({ tenantId: 't1', eventId: 'e1', payload: { invoiceId: 'i1' } });
  assert.deepEqual(value, { invoiceId: 'i1', accepted: true });
  const [record] = await store.getAllRecords();
  assert.equal(record.state, 'succeeded'); assert.equal(record.attemptCount, 1);
  const outbox = await store.getOutbox();
  assert.equal(outbox.length, 1); assert.equal(outbox[0].type, 'webhook.processed');
});

test('completed duplicate returns stored result without invoking handler again', async () => {
  let calls = 0;
  const { processor, store } = setup(async () => ({ sequence: ++calls }));
  const delivery = { tenantId: 't1', eventId: 'same', payload: { amount: 42 } };
  assert.deepEqual(await processor.process(delivery), { sequence: 1 });
  assert.deepEqual(await processor.process(delivery), { sequence: 1 });
  assert.equal(calls, 1); assert.equal((await store.getOutbox()).length, 1);
});

test('conflicting digest is rejected and tenants are isolated', async () => {
  let calls = 0;
  const { processor, store } = setup(async ({ tenantId }) => ({ tenantId, n: ++calls }));
  await processor.process({ tenantId: 'east', eventId: 'evt-9', payload: { amount: 1 } });
  await assert.rejects(processor.process({ tenantId: 'east', eventId: 'evt-9', payload: { amount: 2 } }), (error) => error?.code === 'IDEMPOTENCY_CONFLICT');
  const west = await processor.process({ tenantId: 'west', eventId: 'evt-9', payload: { amount: 1 } });
  assert.equal(west.tenantId, 'west'); assert.equal(calls, 2); assert.equal((await store.getOutbox()).length, 2);
});

test('transient errors retry with injected exponential delays', async () => {
  let calls = 0;
  const transient = Object.assign(new Error('upstream unavailable'), { transient: true });
  const { processor, sleeps, store } = setup(async () => { if (++calls < 3) throw transient; return { ok: true }; });
  assert.deepEqual(await processor.process({ tenantId: 't', eventId: 'retry', payload: { a: 1 } }), { ok: true });
  assert.equal(calls, 3); assert.deepEqual(sleeps, [10, 20]);
  const [record] = await store.getAllRecords(); assert.equal(record.attemptCount, 3); assert.equal(record.state, 'succeeded');
});

test('permanent failure runs once, persists failed, and emits no outbox', async () => {
  let calls = 0; const permanent = new Error('invalid signature');
  const { processor, sleeps, store } = setup(async () => { calls += 1; throw permanent; });
  await assert.rejects(processor.process({ tenantId: 't', eventId: 'bad', payload: {} }), /invalid signature/);
  assert.equal(calls, 1); assert.deepEqual(sleeps, []); assert.equal((await store.getOutbox()).length, 0);
  const [record] = await store.getAllRecords(); assert.equal(record.state, 'failed'); assert.equal(record.attemptCount, 1);
});

test('concurrent duplicate deliveries share one handler and one outbox append', async () => {
  let calls = 0; let release; const gate = new Promise((resolve) => { release = resolve; });
  const { processor, store } = setup(async () => { calls += 1; await gate; return { settled: true }; });
  const delivery = { tenantId: 't', eventId: 'concurrent', payload: { nested: { b: 2, a: 1 } } };
  const first = processor.process(delivery); const second = processor.process(delivery);
  await new Promise((resolve) => setImmediate(resolve)); assert.equal(calls, 1); release();
  assert.deepEqual(await Promise.all([first, second]), [{ settled: true }, { settled: true }]);
  assert.equal((await store.getOutbox()).length, 1);
});

test('authoritative contract marker', async () => {
  await mkdir('ARTIFACTS', { recursive: true });
  await writeFile('ARTIFACTS/verification.json', JSON.stringify({ passed: true, contract: 'TENANT_EVENT_SCOPE', rootCause: 'TENANT_SCOPE_COLLISION' }, null, 2));
});
